import React, { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "react-query";
import { Link } from "react-router-dom";
import { employeeAPI } from "../utils/api";
import LoadingSpinner from "../components/common/LoadingSpinner";
import Modal from "../components/common/Modal";
import { PlusIcon, MagnifyingGlassIcon } from "@heroicons/react/24/outline";
import { SparklesIcon } from "@heroicons/react/24/solid";
import toast from "react-hot-toast";
import { useAuth } from "../context/AuthContext";
import clsx from "clsx";
const STATUS_BADGE = { active:"badge-success", on_leave:"badge-warning", terminated:"badge-danger", resigned:"badge-neutral" };
const emptyEmp = { firstName:"", lastName:"", email:"", phone:"", departmentId:"", salary:"", joinDate:"", employmentType:"full_time" };
export default function Employees() {
  const { isAdmin } = useAuth();
  const qc = useQueryClient();
  const [search, setSearch] = useState("");
  const [page, setPage] = useState(1);
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState(emptyEmp);
  const { data, isLoading } = useQuery(["employees", search, page], () => employeeAPI.getAll({ search, page, limit: 24 }).then(r => r.data), { keepPreviousData: true });
  const createMut = useMutation(employeeAPI.create, { onSuccess: () => { toast.success("Employee created"); qc.invalidateQueries("employees"); setModalOpen(false); setForm(emptyEmp); } });
  if (isLoading) return <LoadingSpinner text="Loading employees…" />;
  const { data: employees = [], pagination } = data || {};
  return (
    <div className="space-y-5 animate-in">
      <div className="flex items-center justify-between">
        <div><h1 className="page-title">Employees</h1><p className="text-slate-500 text-sm mt-0.5">{pagination?.total || 0} total employees</p></div>
        {isAdmin() && <button onClick={() => setModalOpen(true)} className="btn-primary"><PlusIcon className="w-4 h-4" />Add Employee</button>}
      </div>
      <div className="relative max-w-sm"><MagnifyingGlassIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" /><input type="search" placeholder="Search name, email…" value={search} onChange={e => { setSearch(e.target.value); setPage(1); }} className="input pl-9" /></div>
      {employees.length === 0 ? <div className="card text-center py-16 text-slate-500">No employees found</div> : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {employees.map(emp => (
            <Link key={emp.id} to={`/employees/${emp.id}`} className="card hover:shadow-card-hover transition-all group block">
              <div className="flex items-start gap-3">
                <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary-400 to-purple-500 flex items-center justify-center text-white font-bold text-sm flex-shrink-0">{emp.firstName[0]}{emp.lastName[0]}</div>
                <div className="min-w-0 flex-1">
                  <p className="font-semibold text-slate-900 text-sm group-hover:text-primary-600 truncate">{emp.firstName} {emp.lastName}</p>
                  <p className="text-xs text-slate-500 truncate">{emp.email}</p>
                </div>
                <span className={clsx("badge flex-shrink-0", STATUS_BADGE[emp.employmentStatus] || "badge-neutral")}>{emp.employmentStatus?.replace("_"," ")}</span>
              </div>
              <div className="mt-3 pt-3 border-t border-slate-100 flex justify-between text-xs text-slate-400">
                <span>{emp.employeeId}</span>
                <span className="capitalize">{emp.employmentType?.replace("_"," ")}</span>
              </div>
              {emp.aiAttritionScore > 60 && <div className="mt-2 flex items-center gap-1.5 bg-red-50 rounded-lg px-2.5 py-1.5"><SparklesIcon className="w-3 h-3 text-red-500" /><span className="text-xs text-red-600 font-medium">High attrition risk ({Math.round(emp.aiAttritionScore)}%)</span></div>}
            </Link>
          ))}
        </div>
      )}
      {pagination?.pages > 1 && <div className="flex justify-center gap-2">{Array.from({ length: pagination.pages }, (_, i) => i + 1).map(p => (<button key={p} onClick={() => setPage(p)} className={clsx("w-8 h-8 rounded-lg text-sm font-medium transition-colors", p === page ? "bg-primary-600 text-white" : "bg-white text-slate-600 border border-slate-200 hover:bg-slate-50")}>{p}</button>))}</div>}
      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title="Add New Employee" size="lg" footer={<><button onClick={() => setModalOpen(false)} className="btn-secondary">Cancel</button><button onClick={() => createMut.mutate(form)} disabled={createMut.isLoading} className="btn-primary">{createMut.isLoading ? "Creating…" : "Create Employee"}</button></>}>
        <div className="grid grid-cols-2 gap-4">
          {[["firstName","First Name"],["lastName","Last Name"],["email","Email"],["phone","Phone"]].map(([k,l]) => (<div key={k}><label className="label">{l}</label><input type={k==="email"?"email":"text"} className="input" value={form[k]} onChange={e => setForm(f => ({...f,[k]:e.target.value}))} /></div>))}
          <div><label className="label">Salary</label><input type="number" className="input" value={form.salary} onChange={e => setForm(f => ({...f,salary:e.target.value}))} /></div>
          <div><label className="label">Join Date</label><input type="date" className="input" value={form.joinDate} onChange={e => setForm(f => ({...f,joinDate:e.target.value}))} /></div>
        </div>
      </Modal>
    </div>
  );
}
